class Solution:
    def longestSubsequence(self, s: str, k: int) -> int:
        n = len(s)
        dp = [[0] * (k + 1) for _ in range(n + 1)]
        for i in range(1, n + 1):
            for j in range(1, k + 1):
                if int(s[i - 1]) <= j:
                    dp[i][j] = max(dp[i - 1][j], dp[i - 1][j - int(s[i - 1])] + 1)
                else:
                    dp[i][j] = dp[i - 1][j]
        return dp[n][k]
